sql:
SELECT operational_hours
FROM energy_assets
WHERE asset_id = '1';

SELECT asset_id, operational_hours
FROM energy_assets
ORDER BY operational_hours DESC;

external_knowledge:
- The users are maintenance personnel responsible for performing routine and emergency maintenance on energy assets; 
- The maintenance records include all events of maintenance performed on energy assets; 
- The year 2022 and 2023 refer to the time frame of interest for the analysis.

sql:
SELECT asset_id
FROM energy_assets
WHERE asset_id = '1';

external_knowledge:
- 'Operational' status refers to the asset being currently in use; 
- 'Storage' type assets refer to energy storage facilities; 
- 'Subtype '0'' refers to a specific category of storage assets; 
- 'Maintenance date' refers to the date of the last maintenance performed on the asset; 
- 'Access count' refers to the number of times an asset has been accessed.

sql:
SELECT AVG(capacity_electric_kw) AS average_electric_capacity
FROM energy_assets
WHERE asset_type = 'PRODUCTION';

SELECT subtype_name
FROM asset_subtypes
WHERE subtype_id = '1';

SELECT asset_type, installation_date, installation_cost
FROM energy_assets
WHERE installation_date = (
  SELECT MAX(installation_date)
  FROM energy_assets
);
